import React, { useState, useEffect } from 'react';
import { api } from '../services/api';
import { useAuth } from '../context/AuthContext';
import { Trash2, Edit, ExternalLink, PlusCircle, Store, Loader2 } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import ModalNuevaSucursal from './ModalNuevaSucursal';

const Dashboard = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [locales, setLocales] = useState([]);
    const [showModal, setShowModal] = useState(false);
    const [localParaEditar, setLocalParaEditar] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (user?.id) cargarDatos();
    }, [user?.id]);

    const cargarDatos = async () => {
        setLoading(true);
        try {
            const data = await api.getLocalesVendedor(user.id);
            setLocales(data);
        } catch (e) { 
            console.error("Error al cargar locales:", e); 
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async (formData) => {
        try {
            if (localParaEditar) {
                await api.actualizarLocal(localParaEditar._id, formData);
            } else {
                await api.crearLocal({ ...formData, vendedorId: user.id });
            }
            setShowModal(false);
            setLocalParaEditar(null);
            cargarDatos();
        } catch (e) { 
            alert("Error al guardar la sucursal"); 
        }
    };

    const handleEliminar = async (id) => {
        if (window.confirm("¿Estás seguro de eliminar este local? Se borrarán todas sus ofertas permanentemente.")) {
            try {
                await api.eliminarLocal(id);
                cargarDatos();
            } catch (e) {
                alert("No se pudo eliminar el local");
            }
        }
    };

    if (loading) return (
        <div style={loaderStyle}>
            <Loader2 size={40} className="spinner" />
            <p>Cargando tus sucursales...</p>
            <style>{`.spinner { animation: spin 1s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
    );

    return (
        <div style={containerStyle}>
            <header style={headerStyle}>
                <div>
                    <h1 style={{margin:0, color: '#1e293b'}}>Panel de Vendedor</h1>
                    <p style={{color:'#64748b'}}>Gestiona tus sucursales y ofertas activas</p>
                </div>
                <button onClick={() => { setLocalParaEditar(null); setShowModal(true); }} style={btnPlus}>
                    <PlusCircle size={20} /> Nuevo Local
                </button>
            </header>

            {locales.length === 0 ? (
                <div style={emptyStateStyle}>
                    <Store size={48} color="#cbd5e1" />
                    <p>No tienes locales registrados aún.</p>
                    <button onClick={() => setShowModal(true)} style={{...btnPlus, margin: '20px auto'}}>Crear mi primer local</button>
                </div>
            ) : (
                <div style={gridStyle}>
                    {locales.map(local => (
                        <div key={local._id} style={cardStyle}>
                            <div style={cardBadge}><Store size={14}/> Sucursal</div>
                            <h3 style={{marginTop: '15px', color: '#1e293b'}}>{local.nombre}</h3>
                            <p style={addressStyle}>📍 {local.direccion}</p>
                            
                            <div style={actionsContainer}>
                                <button onClick={() => navigate(`/ofertas/${local._id}`)} style={btnManage}>
                                    <ExternalLink size={16} /> Ver Ofertas
                                </button>
                                <button onClick={() => { setLocalParaEditar(local); setShowModal(true); }} style={btnEdit} title="Editar">
                                    <Edit size={16} />
                                </button>
                                <button onClick={() => handleEliminar(local._id)} style={btnDelete} title="Eliminar">
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            {showModal && (
                <ModalNuevaSucursal
                    onClose={() => {setShowModal(false); setLocalParaEditar(null);}}
                    onSave={handleSave}
                    datosIniciales={localParaEditar}
                />
            )}
        </div>
    );
};

// Estética original mantenida
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', minHeight: '100vh' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '40px' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '25px' };
const cardStyle = { background: 'white', padding: '24px', borderRadius: '24px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.05)', position: 'relative', border: '1px solid #f1f5f9' };
const cardBadge = { background: '#f8fafc', color: '#64748b', padding: '6px 12px', borderRadius: '20px', fontSize: '12px', fontWeight: 'bold', display: 'inline-flex', alignItems: 'center', gap: '5px' };
const addressStyle = { color: '#64748b', fontSize: '14px', marginBottom: '25px' };
const actionsContainer = { display: 'flex', gap: '10px' };
const btnPlus = { background: '#e67e22', color: 'white', border: 'none', padding: '14px 24px', borderRadius: '16px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '8px', transition: 'transform 0.2s' };
const btnManage = { flex: 2, background: '#1e293b', color: 'white', border: 'none', borderRadius: '12px', padding: '12px', cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '8px' };
const btnEdit = { flex: 0.5, background: '#f1f5f9', color: '#475569', border: 'none', borderRadius: '12px', padding: '12px', cursor: 'pointer' };
const btnDelete = { flex: 0.5, background: '#fef2f2', color: '#ef4444', border: 'none', borderRadius: '12px', padding: '12px', cursor: 'pointer' };
const loaderStyle = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '80vh', color: '#e67e22' };
const emptyStateStyle = { textAlign: 'center', padding: '80px', background: '#f8fafc', borderRadius: '30px', border: '2px dashed #e2e8f0', color: '#64748b' };

export default Dashboard;
